const FROM = 325, TO = 326;
const input = items[0].json.tags || [];

const ids = new Set();
const tags = [];
for (const t of input) {
  if (!t || typeof t.id !== 'number') continue;
  const id = t.id === FROM ? TO : t.id;
  if (!ids.has(id)) { ids.add(id); tags.push({ id }); }
}

return [{ json: { tags } }];

// ============================================================
// KNOWLEDGE SEARCH ENGINE v2 – Konglomerat Kwarcowy + Legacy
// ============================================================

// --- 1. Pobierz dane produktu ---
const productName = $('Set Product Fields for Agents').item.json.product_name || '';
const category = $('Set Product Fields for Agents').item.json.main_category || '';
const shortDescription = $('Set Product Fields for Agents').item.json.short_description || '';
const currentDescription = $('Set Product Fields for Agents').item.json.current_description || '';
const attributes = $('Set Product Fields for Agents').item.json.attributes || '';

const searchText = `${productName} ${category} ${shortDescription} ${currentDescription}`.toLowerCase();

// --- 2. Sprawdź czy to konglomerat kwarcowy ---
const isQuartz = searchText.includes('konglomerat') ||
  searchText.includes('kwarcow') ||
  searchText.includes('quartz') ||
  searchText.includes('crystal') ||
  searchText.includes('noble ') ||
  searchText.includes('starlight') ||
  searchText.includes('harmonia') ||
  searchText.includes('gobi') ||
  searchText.includes('elegance') ||
  searchText.includes('mystery') ||
  searchText.includes('brilliant') ||
  searchText.includes('taurus') ||
  searchText.includes('glencoe') ||
  searchText.includes('altamonte') ||
  searchText.includes('ambiente') ||
  searchText.includes('badal');

if (!isQuartz) {
  // --- LEGACY PATH: stary silnik dla nie-kwarcowych materiałów ---
  const knowledgeBase = $('Knowledge Base - Materials').item.json.materials_database;
  const materials = knowledgeBase.split('MATERIAŁ: ').filter(s => s.trim().length > 0);
  const foundMaterials = [];
  const foundKeywords = [];

  materials.forEach(material => {
    const lines = material.split('\n');
    const materialName = lines[0].trim().toLowerCase();
    const keywords = [materialName, materialName.replace(' ', ''), materialName.split(' ')[0]];

    if (materialName.includes('konglomerat marmurowy')) keywords.push('aglomarmur', 'marmur', 'kamień');
    if (materialName.includes('pcv') || materialName.includes('pvc')) keywords.push('pcv', 'pvc', 'polichlorek');
    if (materialName.includes('blacha')) keywords.push('trapezowa', 'ryflowana', 'falisty');
    if (materialName.includes('stal')) keywords.push('nierdzewna', 'inox', 'ocynk');
    if (materialName.includes('aluminium')) keywords.push('alu', 'aluminum');
    if (materialName.includes('hpl')) keywords.push('laminat', 'wysokociśnieniowy');

    const found = keywords.some(kw => { if (searchText.includes(kw)) { foundKeywords.push(kw); return true; } return false; });
    if (found) foundMaterials.push(material);
  });

  return [{
    json: {
      is_quartz: false,
      relevant_knowledge: foundMaterials.join('\n\n') || 'Brak dodatkowej wiedzy technicznej dla tego materiału.',
      found_keywords: [...new Set(foundKeywords)].join(', '),
      searched_in: searchText,
      knowledge_found: foundMaterials.length > 0,
      // puste pola kwarcowe (kompatybilność)
      color_info: '',
      collection_info: '',
      application_info: '',
      care_info: '',
      faq_pool: '',
      seo_keywords: '',
      comparisons: '',
      style_recommendations: ''
    }
  }];
}

// ============================================================
// --- QUARTZ PATH: inteligentne wyszukiwanie kwarcowe ---
// ============================================================

// --- 3. Identyfikuj kolor produktu z nazwy ---
const colorLookup = $('Knowledge Base - Materials').item.json.quartz_colors || '';
const colorLines = colorLookup.split('\n').filter(l => l.includes('|'));

let matchedColor = null;
const productNameLower = productName.toLowerCase();

for (const line of colorLines) {
  const parts = line.split('|');
  if (parts.length < 6) continue;
  const colorName = parts[0].trim();
  if (productNameLower.includes(colorName.toLowerCase())) {
    matchedColor = {
      name: colorName,
      collection: parts[1].trim(),
      baseColor: parts[2].trim(),
      description: parts[3].trim(),
      finishes: parts[4].trim(),
      styles: parts[5].trim()
    };
    break;
  }
}

// --- 4. Identyfikuj kolekcję ---
const collectionsDB = $('Knowledge Base - Materials').item.json.quartz_collections || '';
let collectionInfo = '';

const collectionName = matchedColor ? matchedColor.collection : '';
if (collectionName) {
  const collectionMarker = 'KOLEKCJA: ' + collectionName;
  const startIdx = collectionsDB.indexOf(collectionMarker);
  if (startIdx !== -1) {
    const nextCollection = collectionsDB.indexOf('\nKOLEKCJA: ', startIdx + 1);
    collectionInfo = nextCollection !== -1
      ? collectionsDB.substring(startIdx, nextCollection).trim()
      : collectionsDB.substring(startIdx).trim();
  }
}

// --- 5. Identyfikuj kategorię zastosowania ---
const applicationsDB = $('Knowledge Base - Materials').item.json.quartz_applications || '';
let applicationInfo = '';
let applicationCategory = '';

const categoryLower = category.toLowerCase();
if (categoryLower.includes('blat') && categoryLower.includes('kuchenn')) {
  applicationCategory = 'Blaty kuchenne';
} else if (categoryLower.includes('blat') && categoryLower.includes('łazienk')) {
  applicationCategory = 'Blaty łazienkowe';
} else if (categoryLower.includes('schod') || productNameLower.includes('stopień') || productNameLower.includes('podstopień') || productNameLower.includes('stopnic') || productNameLower.includes('podstopnic')) {
  applicationCategory = 'Schody wewnętrzne';
} else if (categoryLower.includes('parapet')) {
  applicationCategory = 'Parapety wewnętrzne';
}

if (applicationCategory) {
  const appMarker = 'ZASTOSOWANIE: ' + applicationCategory;
  const startIdx = applicationsDB.indexOf(appMarker);
  if (startIdx !== -1) {
    const nextApp = applicationsDB.indexOf('\nZASTOSOWANIE: ', startIdx + 1);
    applicationInfo = nextApp !== -1
      ? applicationsDB.substring(startIdx, nextApp).trim()
      : applicationsDB.substring(startIdx).trim();
  }
}

// fallback: jeśli nie znaleziono konkretnej kategorii, daj ogólne info
if (!applicationInfo && applicationsDB) {
  // Szukaj po słowach kluczowych z nazwy produktu
  if (productNameLower.includes('blat kuchenny') || productNameLower.includes('blat kuchenn')) {
    applicationCategory = 'Blaty kuchenne';
  } else if (productNameLower.includes('blat łazienkowy') || productNameLower.includes('blat łazienk')) {
    applicationCategory = 'Blaty łazienkowe';
  } else if (productNameLower.includes('stopień') || productNameLower.includes('podstopień') || productNameLower.includes('stopnic') || productNameLower.includes('podstopnic')) {
    applicationCategory = 'Schody wewnętrzne';
  } else if (productNameLower.includes('parapet')) {
    applicationCategory = 'Parapety wewnętrzne';
  }

  if (applicationCategory) {
    const appMarker = 'ZASTOSOWANIE: ' + applicationCategory;
    const startIdx = applicationsDB.indexOf(appMarker);
    if (startIdx !== -1) {
      const nextApp = applicationsDB.indexOf('\nZASTOSOWANIE: ', startIdx + 1);
      applicationInfo = nextApp !== -1
        ? applicationsDB.substring(startIdx, nextApp).trim()
        : applicationsDB.substring(startIdx).trim();
    }
  }
}

// --- 6. Pobierz pielęgnację, certyfikaty i porównania ---
const careCertsDB = $('Knowledge Base - Materials').item.json.quartz_care_certs || '';

// Wyciągnij sekcję porównań
let comparisons = '';
const compMarker = 'PORÓWNANIA MATERIAŁOWE:';
const compIdx = careCertsDB.indexOf(compMarker);
if (compIdx !== -1) {
  comparisons = careCertsDB.substring(compIdx).trim();
}

// --- 7. Pobierz FAQ z puli ---
const faqDB = $('Knowledge Base - Materials').item.json.quartz_faq || '';

// Wybierz FAQ relevantne dla kategorii
let faqPool = faqDB; // daj pełną pulę, agent wybierze odpowiednie

// --- 8. SEO keywords ---
const seoDB = $('Knowledge Base - Materials').item.json.quartz_seo || '';
let seoKeywords = '';
let styleRecommendations = '';

// Wyciągnij keywords per kategoria z seoDB
if (applicationCategory === 'Blaty kuchenne') {
  seoKeywords = 'blat kuchenny z konglomeratu kwarcowego, blat kuchenny kwarcowy, blaty kuchenne z kamienia kwarcowego, nieporowaty blat kuchenny, higieniczny blat kuchenny';
} else if (applicationCategory === 'Blaty łazienkowe') {
  seoKeywords = 'blat łazienkowy z konglomeratu kwarcowego, wodoodporny blat łazienkowy, blat pod umywalkę kwarcowy, blat łazienkowy kamień kwarcowy';
} else if (applicationCategory === 'Schody wewnętrzne') {
  seoKeywords = 'schody z konglomeratu kwarcowego, stopnica kwarcowa, stopień schodowy kamień kwarcowy, schody wewnętrzne konglomerat, podstopnica kwarcowa';
} else if (applicationCategory === 'Parapety wewnętrzne') {
  seoKeywords = 'parapet wewnętrzny z konglomeratu kwarcowego, parapet kwarcowy, parapet z kamienia kwarcowego, parapet na wymiar konglomerat';
}

// Dodaj keywords kolorystyczne jeśli znaleziono kolor
if (matchedColor) {
  const colorKw = matchedColor.baseColor + ' konglomerat kwarcowy, ' + matchedColor.baseColor + ' kamień kwarcowy';
  seoKeywords = seoKeywords ? seoKeywords + ', ' + colorKw : colorKw;
}

// Style wnętrz
if (matchedColor && matchedColor.styles) {
  const stylesArr = matchedColor.styles.split(',').map(s => s.trim());
  const styleMap = seoDB.match(/STYLE WNĘTRZ[\s\S]*?(?=TOP 10|$)/)?.[0] || '';
  styleRecommendations = `Rekomendowane style wnętrz dla ${matchedColor.name}: ${stylesArr.join(', ')}`;
}

// --- 9. Zbuduj pakiet wiedzy materiałowej ---
const materialsDB = $('Knowledge Base - Materials').item.json.materials_database || '';
let quartzMaterialInfo = '';
const quartzMarker = 'MATERIAŁ: Konglomerat kwarcowy';
const qIdx = materialsDB.indexOf(quartzMarker);
if (qIdx !== -1) {
  const nextMat = materialsDB.indexOf('\nMATERIAŁ: ', qIdx + 1);
  quartzMaterialInfo = nextMat !== -1
    ? materialsDB.substring(qIdx, nextMat).trim()
    : materialsDB.substring(qIdx).trim();
}

// --- 10. Kompiluj wynik ---
const colorInfoStr = matchedColor
  ? `Kolor: ${matchedColor.name} | Kolekcja: ${matchedColor.collection} | Odcień bazowy: ${matchedColor.baseColor} | Opis: ${matchedColor.description} | Wykończenia: ${matchedColor.finishes} | Style: ${matchedColor.styles}`
  : 'Kolor nierozpoznany w bazie – użyj ogólnych informacji o konglomeracie kwarcowym';

// Relevant knowledge = materiał + zastosowanie + kolekcja (skompresowane)
const relevantKnowledge = [
  quartzMaterialInfo,
  applicationInfo ? `\n${applicationInfo}` : '',
  collectionInfo ? `\nINFO O KOLEKCJI: ${collectionInfo.substring(0, 500)}` : '',
  matchedColor ? `\nKOLOR PRODUKTU: ${colorInfoStr}` : ''
].filter(Boolean).join('\n');

return [{
  json: {
    is_quartz: true,
    relevant_knowledge: relevantKnowledge,
    found_keywords: ['konglomerat kwarcowy', applicationCategory, matchedColor?.name, matchedColor?.collection].filter(Boolean).join(', '),
    searched_in: searchText,
    knowledge_found: true,
    color_info: colorInfoStr,
    collection_info: collectionInfo.substring(0, 800),
    application_info: applicationInfo,
    care_info: careCertsDB.substring(0, careCertsDB.indexOf('PORÓWNANIA') > 0 ? careCertsDB.indexOf('PORÓWNANIA') : careCertsDB.length).trim(),
    faq_pool: faqPool,
    seo_keywords: seoKeywords,
    comparisons: comparisons,
    style_recommendations: styleRecommendations
  }
}];

// Pobierz dane z agregatora
const rawData = items[0].json;

let outputData;

if (rawData.output) {
  // Wyczyść JSON z backtickow markdown
  let cleaned = rawData.output;
  // Usuń ```json ... ``` oraz ``` ... ```
  cleaned = cleaned.replace(/^\s*```(?:json)?\s*\n?/i, '').replace(/\n?\s*```\s*$/i, '');
  cleaned = cleaned.trim();

  try {
    outputData = JSON.parse(cleaned);
  } catch (e) {
    // Fallback: spróbuj wyciągnąć JSON z tekstu
    const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try {
        outputData = JSON.parse(jsonMatch[0]);
      } catch (e2) {
        // Ostateczny fallback
        outputData = {
          writing_style: 'profesjonalny i techniczny',
          writing_tone: 'przyjazny i ekspercki',
          search_intent: 'commercial',
          target_audience: 'właściciele domów i mieszkań, projektanci wnętrz',
          product_benefits: [],
          common_questions: [],
          technical_keywords: [],
          application_keywords: []
        };
      }
    } else {
      outputData = {
        writing_style: 'profesjonalny i techniczny',
        writing_tone: 'przyjazny i ekspercki',
        search_intent: 'commercial',
        target_audience: 'właściciele domów i mieszkań, projektanci wnętrz',
        product_benefits: [],
        common_questions: [],
        technical_keywords: [],
        application_keywords: []
      };
    }
  }
} else if (rawData.data && Array.isArray(rawData.data)) {
  outputData = rawData.data[0];
} else {
  outputData = rawData;
}

// Funkcja pomocnicza do bezpiecznego join
const safeJoin = (value, separator = ', ') => {
  if (Array.isArray(value)) {
    return value.join(separator);
  }
  return value || '';
};

return [
  {
    json: {
      writing_style: safeJoin(outputData.writing_style),
      writing_tone: safeJoin(outputData.writing_tone),
      search_intent: safeJoin(outputData.search_intent),
      target_audience: safeJoin(outputData.target_audience),
      product_benefits: safeJoin(outputData.product_benefits),
      common_questions: safeJoin(outputData.common_questions),
      technical_keywords: safeJoin(outputData.technical_keywords),
      application_keywords: safeJoin(outputData.application_keywords),
      main_keyword: $('Set Product Fields for Agents').item.json.product_name
