// ============================================================
// FINAL DESCRIPTION ASSEMBLY v3.1 — rozszerzony regex FAQ
// ============================================================

const intro = ($('Product Intro Generator').item.json.output || '').trim();
const benefits = ($('Product Benefits Generator').item.json.output || '').trim();
const specs = ($('Technical Specs Generator').item.json.output || '').trim();
const faq = ($('FAQ Generator').item.json.output || '').trim();
const cta = ($('CTA Generator').item.json.output || '').trim();

function cleanIntro(text) {
  return text
    .replace(/^\s*#{1,3}\s+.*\n+/, '')
    .trim();
}

function cleanFaq(text) {
  // Usuń WSZYSTKIE meta-zdania przed pierwszym pytaniem **
  // Łapie: "Oto 6 pytań FAQ...", "Oto pytania i odpowiedzi...", 
  // "Poniżej FAQ...", "Sekcja FAQ...", "Przygotowałem..."
  // Strategia: wytnij wszystko przed pierwszym **
  const firstBold = text.indexOf('**');
  if (firstBold > 0) {
    // Jest tekst przed pierwszym ** — sprawdź czy to meta-zdanie
    const before = text.substring(0, firstBold).trim();
    // Jeśli to krótki tekst (< 500 znaków) i nie zawiera nagłówka ## — to meta-zdanie
    if (before.length < 500 && !before.includes('##')) {
      text = text.substring(firstBold);
    }
  }
  return text.trim();
}

function cleanCta(text) {
  return text
    .replace(/^\s*#{1,3}\s+.*\n+/, '')
    .trim();
}

function ensureBenefitsHeader(text) {
  if (/^\s*##\s+Główne korzyści/i.test(text)) {
    return text;
  }
  return '## Główne korzyści:\n\n' + text;
}

const sections = [];

if (intro) {
  sections.push(cleanIntro(intro));
}

if (benefits) {
  sections.push(ensureBenefitsHeader(benefits));
}

if (specs) {
  sections.push(specs);
}

sections.push('---');

if (faq) {
  sections.push(cleanFaq(faq));
}

if (cta) {
  sections.push(cleanCta(cta));
}

let finalOutput = sections.join('\n\n');

finalOutput = finalOutput
  .replace(/^\s*```(?:markdown|html)?\s*\n/gm, '')
  .replace(/\n```\s*$/gm, '')
  .replace(/```(?:markdown|html)?\s*\n([\s\S]*?)\n```/g, '$1');

finalOutput = finalOutput.replace(/\n{3,}/g, '\n\n');

return [{ json: { output: finalOutput } }];

